mapper.select:
        (select * from search where pinned = 1)
		union all
		(select * from search where pinned = 0 order by created_at desc  

        limit #{limit}
        )
		order by
		    pinned desc,
		    case 
		        when pinned = 1 then created_at 
		    end desc,
		    case 
		        when pinned = 0 then created_at
		    end desc;
